head.script:
scwin.gr_odrWrkPathStpDetail_beforeCellChgInfos;

scwin.interval01;
scwin.rtnFlag;

scwin.memJson;
scwin.lobranCd;
scwin.lobranNm;
scwin.userId;
scwin.loUpperLobranCd;

scwin.wrkLobranCd;
scwin.wrkLobranNm;
scwin.internalSellLodeptCd;
scwin.internalSellLodeptNm;
scwin.wrkLobranCdRow;

scwin.gv_rtnValue;
scwin.gv_modifyYn;

scwin.rail_yn;
scwin.v_odrWrkStpSeq;
scwin.v_odrWrkStpSeqMax;

scwin.udc_objNm;

scwin.f_Retrieve_submitFlag;
scwin.ds_odrCntrWrkPath_json;

scwin.gr_odrWrkPathStpDetailColIdx;
scwin.gr_odrWrkPathStpDetailRowIdx;

scwin.tempArray;

scwin.v_dptWrkPlCd;
scwin.v_bizDomCd;


scwin.onpageload = function() {
    document.body.addEventListener('keydown', scwin.body_onkeydown);

    //전역변수값 셋팅함수.
	scwin.initSetVal();

    const codeOptions1 = [
        { grpCd: "SD113", compID: "acb_cnd_odrKndCd"},  //구분 코드셋팅처리. 
        { grpCd : "OP171", compID : "gr_odrWrkPathStpDetail:fullEmptyClsCd"}, //F/E
    ];
    $c.data.setCommonCode(codeOptions1, scwin.commonCodeCallBack01);
};

//f_cfIsClose 함수 수행.
scwin.body_onkeydown = function (e) {
    if(e.keyCode == 27) {
        /*
        let rt = [scwin.ds_parent];
        $c.win.closePopup(rt);
        */
        $c.win.closePopup();
    }
};

scwin.initSetVal = function() {
    scwin.memJson = $c.data.getMemInfo();
    scwin.lobranCd = scwin.memJson.lobranCd;
    scwin.lobranNm = scwin.memJson.lobranNm;
    scwin.userId = scwin.memJson.userId;
    scwin.loUpperLobranCd = scwin.memJson.loUpperLobranCd;

    scwin.wrkLobranCd = scwin.lobranCd; // 작업점소코드
    scwin.wrkLobranNm = scwin.lobranNm; // 작업점소명
    scwin.internalSellLodeptCd = "";
    scwin.internalSellLodeptNm = "";
    scwin.wrkLobranCdRow = 0;

    // 사용자 040239 (채태종) 의 경우 운송 부서를 4A5(인천제강운송)으로 설정
    if(scwin.userId == "040239"){
        scwin.internalSellLodeptCd = "4A5";
        scwin.internalSellLodeptNm = "인천제강운송";
    }

    //변경여부 상위 화면으로 반환
    scwin.gv_rtnValue = 0;
    scwin.gv_modifyYn = false;

    scwin.rail_yn = "";
    scwin.v_odrWrkStpSeq = 0;
    scwin.v_odrWrkStpSeqMax = 0;

    scwin.rtnFlag = false;

    scwin.f_Retrieve_submitFlag = false;

    scwin.gr_odrWrkPathStpDetailColIdx = "";
    scwin.gr_odrWrkPathStpDetailRowIdx = "";

    scwin.tempArray = [];

    scwin.v_dptWrkPlCd = "";
    scwin.v_bizDomCd = "";
};

scwin.sleep = function(ms) {
    return new Promise((r) => setTimeout(r, ms));
};

scwin.isIdExist = function (id) {
    if($('#' + id).length > 0) {
        scwin.rtnFlag = true;
    }
};

scwin.gr_odrWrkPathStpDetail_wrkStpCd_setEmptyVal = function (rowIndex) {
    scwin.sleep(0).then(function () {
        scwin.rtnFlag = false;
        var elementId = $p.getComponentById(gr_odrWrkPathStpDetail.id).id+"_cell_"+rowIndex+"_7 nobr";
        scwin.isIdExist(elementId);
        if(scwin.rtnFlag) {
            if($('#' + elementId).text().trim() == ":") {
                $('#' + elementId).empty();
            } 
        } else {
            scwin.isIdExist(elementId);
            scwin.interval01 = setInterval(async function() {
                if(scwin.rtnFlag == true) {
                    if($('#' + elementId).text().trim() == ":") {
                        $('#' + elementId).empty();
                    } 
                    clearInterval(scwin.interval01);
                }
            }, 30);
        }

    });
};




scwin.commonCodeCallBack01 = async function() {
    let ds_obj = $p.getComponentById(acb_cnd_odrKndCd.getDataListInfo().id);

    var fn_colFilter01 = function(cellData, tmpParam, rowIdx){
        if(cellData == "1"){
            return true;
        }
        return false;   // return이 true인 경우 적용하고 false인 경우 넘김
    };

    var fn_colFilter02 = function(cellData, tmpParam, rowIdx){
        if(cellData == "C"){
            return true;
        }
        return false;   // return이 true인 경우 적용하고 false인 경우 넘김
    };

    ds_obj.setColumnFilter( 
        {type:'func', colIndex:'fltrCd3', key:fn_colFilter01, condition:'and'}
    );

    ds_obj.setColumnFilter( 
        {type:'func', colIndex:'fltrCd1', key:fn_colFilter02, condition:'and'}
    );

    ds_obj.insertRow(0);
    ds_obj.setCellData(0, "cd", "");
    ds_obj.setCellData(0, "cdNm", "전체");

    var options = {};
    options.sortIndex = "cd sortSeq";
    options.sortOrder = "1 1";     //오른차순:"1", 내림차순"-1"
    ds_obj.multisort(options);

    ds_obj.reform();

    await scwin.f_OnLoad();
};

//-------------------------------------------------------------------------
// 선택된 오더 유형별 화면 설정을 변경한다.
//-------------------------------------------------------------------------
scwin.f_setDisplayOdrKndCd = function(odrKndCd) {
    switch (odrKndCd) {
        case DsConstants.ODR_KND_CD_EXP_GNRL_CNTR_ODR:   // 컨테이너 수출일반 오더


            break;
        case DsConstants.ODR_KND_CD_IMP_STV_CNTR_ODR:    // 컨테이너 수입하역 오더  
        case DsConstants.ODR_KND_CD_EXP_STV_CNTR_ODR:    // 컨테이너 수출하역 오더

            gr_odrCntrWrkPath.setColumnVisible("qty", false);
            gr_odrCntrWrkPath.setColumnVisible("cntrTypCd", false);
            gr_odrCntrWrkPath.setColumnVisible("arvWrkPlNm", false);

            break;
        default :   

            gr_odrCntrWrkPath.setColumnVisible("qty", false);
            gr_odrCntrWrkPath.setColumnVisible("cntrTypCd", true);
            gr_odrCntrWrkPath.setColumnVisible("arvWrkPlNm", true);

            // 그리드 항목 설정

            break;  
    }
};



//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.f_OnLoad = async function() {

    // 초기화
    await scwin.f_defaultValue();

    var arrParent;

    if(Object.keys($c.data.getParameter()).length > 0) {
        arrParent = $c.data.getParameter()[Object.keys($c.data.getParameter())[0]];

        ed_odrNo.setValue(arrParent[0]);
        hid_cntrSeq.setValue(arrParent[1]);
        hid_qryClsCd.setValue(arrParent[2]);

        //조회
        await scwin.f_Retrieve();
        scwin.f_Update();
    }
};


//-------------------------------------------------------------------------
// 초기값 설정
//-------------------------------------------------------------------------
scwin.f_defaultValue = async function() {
    // DataSet Header 초기화
    dma_lobranQueryCondition.set("lobranCd", scwin.lobranCd);
    dma_lobranQueryCondition.set("lobranClsCd", "T");
    dma_lobranQueryCondition.set("deptmentCd", DsConstants.TRANS_DEPARTMENT);
    dma_lobranQueryCondition.set("useYn", DsConstants.YN_YES);


    //여기선 오더번호 비활성화처리.
    // KeyData 비활성화
    //cfDisableKeyData();
    ed_odrNo.setReadOnly(true);

    // 그리드 행추가 / 삭제 /취소 버튼 비활성화
  	//cfDisableAllBtn();
    btn_InsertRow.setDisabled(true);  //행삽입 버튼 비활성화.
    btn_DeleteRow.setDisabled(true);  //udc(행삭제) 버튼 비활성화. 
    btn_UndoMark.setDisabled(true);   //udc(취소) 버튼 비활성화.

  	$c.gus.cfEnableBtnOnly([btn_Close]);         //닫기 버튼 활성화. 
    $c.gus.cfDisableBtn([btn_Update,btn_Save]);  //수정,저장 버튼 비활성화. 

  	// 조회 DataSet 초기화
	dma_orderSearch.set("odrNo","");

	lay_ctrtClntNm.setValue("");	// 계약거래처명 설정	
	lay_ctrtNo.setValue("");	// 계약번호 설정	
	td_realMchtClntNm.setValue("실화주");
	lay_realMchtclntNm.setValue("");	// 실화주명 설정
	lay_odrKndNm.setValue("");	// 오더종류 설정

    hid_ctrtClntNo.setValue("");	// 계약거래처 코드 설정	
	hid_ctrtNo.setValue("");	// 계약번호 설정	
	hid_realMchtclntNo.setValue("");	// 실화주 코드 설정

	// 로그인 사용자 물류점소 - 운송부서 조회
  	dma_lobranQueryCondition.set("deptmentCd",DsConstants.TRANS_DEPARTMENT);
    ds_lobran.removeAll();

    //submit 처리.
    let objSubmit = await $c.sbm.execute(sbm_retrieveLobranTrans);

    if(objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {   
        await scwin.sbm_retrieveLobranTrans_submitdone();
    }
};

scwin.sbm_retrieveLobranTrans_submitdone = async function (e) {
    if(ds_lobran.getRowCount() > 0){
        // 사용자 040239 (채태종) 의 경우 운송 부서를 4A5(인천제강운송)으로 설정
        if(scwin.userId == "040239"){
            scwin.internalSellLodeptCd = "4A5";
            scwin.internalSellLodeptNm = "인천제강운송";
        } else {
            var nRow = ds_lobran.getRowPosition();
            if(nRow == undefined || nRow == null || nRow == "") {
                nRow = 0;
            }

            scwin.internalSellLodeptCd = ds_lobran.getCellData(nRow, "lobranCd");  // 운송부서코드
            scwin.internalSellLodeptNm = ds_lobran.getCellData(nRow, "lobranNm");  // 운송부서명
        }
    }

    gr_odrCntrWrkPath.setReadOnly("column","ctrtWrkPathSeq",false);
    hid_chkUseFilter.setValue(true);

    // 그리드 총건수 초기화
    totalRows.setValue(ds_odrCntrWrkPath.getRowCount());
    totalRows2.setValue(ds_odrWrkPathStepDetail.getRowCount())

    //to-do W-gear 가 있어야 가능함.
    //cfSetIMEModeActiveObjects(gr_odrWrkPathStpDetail);      

    ed_odrNo.focus();
};


//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function() {

    var rail_yn = "";
    var v_odrWrkStpSeq = 0; 
    var v_odrWrkStpSeqMax = 0;

    let ret = await $c.gus.cfValidate([ed_odrNo]);
    if(ret) {
        var odrNo = ed_odrNo.getValue().replace(/\s*$/, '');

        scwin.v_dptWrkPlCd = "";
        scwin.v_bizDomCd = "";

        //cfDisableKeyData();
        ed_odrNo.setReadOnly(true);

        //cfDisableAllBtn();
        //cfEnableBtnOnly([btnClose]);
        //cfEnableBtnOnly([btnSave]);
        btn_InsertRow.setDisabled(true);  //행삽입 버튼 비활성화.
        btn_DeleteRow.setDisabled(true);  //udc(행삭제) 버튼 비활성화. 
        btn_UndoMark.setDisabled(true);   //udc(취소) 버튼 비활성화.

        $c.gus.cfEnableBtnOnly([btn_Close,btn_Save]);

        ds_order.removeAll(); //조회용
        ds_odrCntrSummary.removeAll();
        ds_ctrtWrkPath.removeAll();
        ds_odrWrkPathStep.removeAll();
        ds_odrCntrWrkPath.removeAll();
        ds_ctrtWrkPathStep.removeAll();
        ds_odrWrkPathStepDetail.removeAll();

        // 그리드 총건수 초기화
        totalRows.setValue(0);
        totalRows2.setValue(0);

        /************************************************************
        * 작업장구분 Lokkup DataSet Setting 시작
        ************************************************************/
        dma_wrkPlClsCd.set("grpCd", "LO121");
        dma_wrkPlClsCd.set("cd", "");
        dma_wrkPlClsCd.set("cdNm", "");

        //submit 처리.
        let objSubmit = await $c.sbm.execute(sbm_wrkPlClsCd);
        if(objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {  
            await scwin.sbm_wrkPlClsCd_submitdone();
        }
        /************************************************************
        * 작업장구분 Lokkup DataSet Setting 끝
        ************************************************************/

        /************************************************************
        * 작업단계 LookUp DataSet Setting 시작
        ************************************************************/
        objSubmit = await $c.sbm.execute(sbm_LkStepNo);
        if(objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {  
            await scwin.sbm_LkStepNo_submitdone();
        }
        /************************************************************
        * 작업단계 LookUp DataSet Setting 끝
        ************************************************************/

        dma_orderSearch.set("odrNo", odrNo);

        scwin.gv_modifyYn = false;

        //flag 값 초기화.
        scwin.f_Retrieve_submitFlag = false;

        objSubmit = await $c.sbm.execute(sbm_retrieve);
        if(objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {  
            //dataList(ds_ctrtWrkPath(작업경로 콤보), ds_odrCntrWrkPath(gr_odrCntrWrkPath)) onload 시점과
            //트랜잭션 완료 시점이 달라 임의로 json 객체 통하여 재셋팅처리.
            scwin.ds_odrCntrWrkPath_json = objSubmit.responseJSON.OUT_DS2;

            await scwin.sbm_retrieve_submitdone();
        }
    };
};

scwin.sbm_wrkPlClsCd_submitdone = async function (e) {
    for(var i=0;i<ds_wrkPlClsCd.getRowCount();i++) {
        if(Number(ds_wrkPlClsCd.getCellData(i, "sortSeq")) != 20) {
            ds_wrkPlClsCd.setCellData(i, "sortSeq2", Number(ds_wrkPlClsCd.getCellData(i, "sortSeq")));
        } else {
            var code = ds_wrkPlClsCd.getCellData(i, "cd");
            if(code == "L") {
                ds_wrkPlClsCd.setCellData(i, "sortSeq2", 20);
            } else if(code == "D") {
                ds_wrkPlClsCd.setCellData(i, "sortSeq2", 21);
            } else if(code == "G") {
                ds_wrkPlClsCd.setCellData(i, "sortSeq2", 22);
            } else if(code == "R") {
                ds_wrkPlClsCd.setCellData(i, "sortSeq2", 23);
            } else if(code == "S") {
                ds_wrkPlClsCd.setCellData(i, "sortSeq2", 24);
            } else if(code == "M") {
                ds_wrkPlClsCd.setCellData(i, "sortSeq2", 25);
            } else if(code == "Z") {
                ds_wrkPlClsCd.setCellData(i, "sortSeq2", 26);
            }
        }
    }

    ds_wrkPlClsCd.sort("sortSeq2",0);


    ds_wrkPlClsCd.insertRow(0);
    ds_wrkPlClsCd.setCellData(0,"cd", " ");
    ds_wrkPlClsCd.setCellData(0,"cdNm", "→");
};

scwin.sbm_LkStepNo_submitdone = async function (e) {
};

scwin.sbm_retrieve_submitdone = async function (e) {
    scwin.f_Retrieve_submitFlag = true;


    //dataList onload 수행이 선행된 이후 트랜잭션 완료되므로 한번 더 호출토록 추가.
    await scwin.ds_order_ondataload();           //1순위 처리
    await scwin.ds_ctrtWrkPath_ondataload();     //2순위 처리
    await scwin.ds_odrCommodity_ondataload();

    //dataList(ds_ctrtWrkPath(작업경로 콤보), ds_odrCntrWrkPath(gr_odrCntrWrkPath)) onload 시점과
    //트랜잭션 완료 시점이 달라 임의로 json 객체 통하여 재셋팅처리.
    ds_odrCntrWrkPath.removeAll();
    ds_odrCntrWrkPath.setJSON(scwin.ds_odrCntrWrkPath_json);
    ds_odrCntrWrkPath.reform();

    scwin.ds_odrCntrWrkPath_json = null;

    /************************************************************************************************
    * for=ds_odrCntrWrkPath event=OnLoadCompleted 시작
    ************************************************************************************************/
    totalRows.setValue(ds_odrCntrWrkPath.getRowCount());

    if( ds_order.getRowCount() > 0 && ds_odrCntrWrkPath.getRowCount() == 0 ){
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
    }

    //for=ds_odrCntrWrkPath event=OnRowPosChanged 이벤트 호출위해 임의로 RowPosition 0으로 지정.
    //if(ds_odrCntrWrkPath.getRowCount() > 0) {
    //    ds_odrCntrWrkPath.setRowPosition(0);
    //}

    //상기로직에서 하기로직으로 변경.
    //사유: 트랜잭션 완료시점이 미묘하게 달라져서 OnRowPosChanged 이벤트 로직을 그대로 셋팅처리.
    var row = 0;
    if(Number(ds_odrCntrWrkPath.getCellData(row, "ctrtWrkPathSeq")) > 0){      
        if(ds_odrWrkPathStepDetail.getRowCount() > 0){
            // 이미 작업단계가 존재함.

        } else {
            // 작업단계 검색 조건 설정
            dma_searchWrkStep.set("odrNo", ds_odrCntrWrkPath.getCellData(row, "odrNo"));
            dma_searchWrkStep.set("cntrSeq", ds_odrCntrWrkPath.getCellData(row, "cntrSeq"));
            dma_searchWrkStep.set("odrWrkPathSeq", ds_odrCntrWrkPath.getCellData(row, "odrWrkPathSeq"));
            dma_searchWrkStep.set("ctrtNo", ds_odrCntrWrkPath.getCellData(row, "ctrtNo"));
            dma_searchWrkStep.set("ctrtWrkPathSeq", ds_odrCntrWrkPath.getCellData(row, "ctrtWrkPathSeq"));

            await scwin.f_RetrieveWorkStep();
        }
        totalRows2.setValue(ds_odrWrkPathStepDetail.getRowCount()); 
    }

    // 해당 품명의 실적 발생여부를 확인하여 수정 가능 항목을 설정한다.
    // 실적 발생시 수정할 수 없다.
    // 실적 발생여부를 조회하여 수정항목을 설정한다.
    if(row > -1 && btn_Update.getDisabled()){
        if(scwin.f_chkResultsConfirmationCommodity(row)){
            gr_odrCntrWrkPath.setReadOnly("column","ctrtWrkPathSeq",true);
            gr_odrWrkPathStpDetail.setDisabled(true);
        } else {
            gr_odrCntrWrkPath.setReadOnly("column","ctrtWrkPathSeq",false);
            gr_odrWrkPathStpDetail.setDisabled(false);
        }
    }
    /************************************************************************************************
    * for=ds_odrCntrWrkPath event=OnLoadCompleted 끝
    ************************************************************************************************/

    hid_chkUseFilter.setValue(true);

    gr_odrCntrWrkPath.setReadOnly("column","ctrtWrkPathSeq",true);
    gr_odrWrkPathStpDetail.setDisabled(true);

    if(Number(ds_order.getCellData(0, "odrDcsnYn")) != DsConstants.YN_YES) {   
        $c.gus.cfEnableBtnOnly([btn_Update]);
        $c.gus.cfDisableBtnOnly([btn_Save]);
    } else {
        $c.gus.cfEnableBtnOnly([btn_Update]);
        $c.gus.cfDisableBtnOnly([btn_Save]);
    }

    if(Number(ds_order.getCellData(0, "odrCompleteYn")) != DsConstants.YN_YES) {   
        $c.gus.cfEnableBtnOnly([btn_Update]);
        $c.gus.cfDisableBtnOnly([btn_Save]);
    } else {
        $c.gus.cfDisableBtnOnly([btn_Update, btn_Save]);
    }

    if(ds_odrCntrWrkPath.getRowCount() > 0 && ds_order.getCellData(0, "odrDcsnYn") != DsConstants.YN_YES && ds_order.getCellData(0, "odrCompleteYn") != DsConstants.YN_YES) {
        // 작업경로가 저장되지 않은 경우 수정모드로 설정
        if(Number(ds_odrCntrWrkPath.getCellData(ds_odrCntrWrkPath.getRowPosition(), "odrWrkPathSeq")) == 0){
            scwin.f_Update();
        }
    }

    $c.gus.cfDisableBtnOnly([btn_InsertRow, btn_DeleteRow, btn_UndoMark]);

    if(ds_order.getCellData(0, "odrDcsnYn") != DsConstants.YN_YES && ds_odrWrkPathStep.getRowCount() > 0) {
        //to-do 부모화면에서 hid_chkReterieve 있는지 확인필요.
        //parent.iFrame0.hid_chkReterieve.value = ""; // 재조회
    }

    hid_chkReterieve.setValue("retrieveIn");  // 조회 성공여부 
};


//-------------------------------------------------------------------------
// 조회 조건 초기화
//-------------------------------------------------------------------------
scwin.f_FieldClear = function () {
    $c.gus.cfInitObjects([ed_odrNo]);
    ed_odrNo.focus();
};

//-------------------------------------------------------------------------
// 선택된 작업경로에 대한 작업 단계 조회
//-------------------------------------------------------------------------
scwin.f_RetrieveWorkStep = async function () {
    if(Number(dma_searchWrkStep.get("ctrtWrkPathSeq")) == 0){        
        return;
    }

    // 선택된 작업경로별 작업단계 조회
    //submit 처리.
    let objSubmit = await $c.sbm.execute(sbm_searchWorkStep);
    if(objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {  
        await scwin.sbm_searchWorkStep_submitdone();
    }
};

scwin.sbm_searchWorkStep_submitdone = async function (e) {
    // 작업단계 그리드에 설정
    await scwin.f_setWorkPathStepDetail();
};


//-------------------------------------------------------------------------
// 선택된 그리드에 작업단계 삽입 : 첫번째열을 선택한 경우 해당열 아래에 행삽입 후 이전 작업단계 정보 복사
//-------------------------------------------------------------------------
scwin.f_InsertRow = async function () {
    //현행포함 이후의 행들에 작업지시나 실적이 있을시 행을 삽입할 수 없다.
    for(var i = ds_odrWrkPathStepDetail.getRowPosition() ; i < ds_odrWrkPathStepDetail.getRowCount() ; i++ ) {

        if( Number(ds_odrWrkPathStepDetail.getCellData(i, "transRsltsSeq")) > 0 ) {
            await $c.gus.cfAlertMsg("삽입하고자 하는 이후의 작업단계에 운송실적이 발생되어서 삽입할 수 없습니다.");
            return;
        } else if ( ds_odrWrkPathStepDetail.getCellData(i, "transWrkIndictNo") != "" ) {
            await $c.gus.cfAlertMsg("삽입하고자 하는 이후의 작업단계에 운송작업지시가 발생되어서 삽입할 수 없습니다.");
            return;
        }

    }

    if(Number(ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(), "odrWrkStpSeq")) % 10 < 9){
        // 선택된 행 아래에 새로운 행 삽입
        let row = ds_odrWrkPathStepDetail.getRowPosition();
  		ds_odrWrkPathStepDetail.insertRow(row+1);

        if(scwin.gr_odrWrkPathStpDetailColIdx != undefined && scwin.gr_odrWrkPathStpDetailColIdx != null && scwin.gr_odrWrkPathStpDetailColIdx != "") {
            gr_odrWrkPathStpDetail.setFocusedCell(row+1, scwin.gr_odrWrkPathStpDetailColIdx);
        } else {
            gr_odrWrkPathStpDetail.setFocusedCell(row+1, 0);
        }

        //행삽입 이후 rowChange 이벤트 발생하므로 수동으로 이벤트 추가.
        scwin.ds_odrWrkPathStepDetail_OnRowPosChanged();

        scwin.f_CopyDataRow(ds_odrWrkPathStepDetail, ds_odrWrkPathStepDetail.getRowPosition()-1, ds_odrWrkPathStepDetail.getRowPosition());
        await scwin.f_setWorkStepInfoRefresh2(ds_odrWrkPathStepDetail.getRowPosition());
    } else {
        await $c.gus.cfAlertMsg("더이상 작업단계를 추가할수 없습니다."); //작업단계을(를) 확인하여 주십시오
        return;
    }

    if(ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(), "odrNo").substring(0,3)== "BC4" && scwin.rail_yn == "Y"
        && scwin.userId != "991166" && scwin.userId != "030706" ){
        if(Number(ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(), "odrWrkStpSeq")) >= scwin.v_odrWrkStpSeq){
            await $c.win.alert("철송이후 단계를 수정하실수 없습니다.");
            await scwin.f_Retrieve();
        }

    } 
};



//-------------------------------------------------------------------------
// 선택된 그리드에 작업단계 삭제
//-------------------------------------------------------------------------
scwin.f_DeleteRow = async function () {
    //현행포함 이후의 행들에 작업지시나 실적이 있을시 행을 삭제할 수 없다.
    for(var i = ds_odrWrkPathStepDetail.getRowPosition() ; i < ds_odrWrkPathStepDetail.getRowCount() ; i++ ) {

        if( Number(ds_odrWrkPathStepDetail.getCellData(i, "transRsltsSeq")) > 0 ) {
            await $c.gus.cfAlertMsg("삭제하고자 하는 이후의 작업단계에 운송실적이 발생되어서 삭제할 수 없습니다.");
            return;
        }

        if( i - 1 > -1 ) {
            if ( Number(ds_odrWrkPathStepDetail.getCellData(i - 1, "transRsltsSeq")) > 0 ) {
                await $c.gus.cfAlertMsg("삭제하고자 하는 단계가 포함된 운송작업단계에 운송실적이 발생되어서 삭제할 수 없습니다.");
                return;
            }
        }

        if ( ds_odrWrkPathStepDetail.getCellData(i, "transWrkIndictNo") != "" ) {
            await $c.gus.cfAlertMsg("삭제하고자 하는 이후의 작업단계에 운송작업지시가 발생되어서 삭제할 수 없습니다.");
            return;
        }

        if( i - 1 > -1 ) {
            if ( ds_odrWrkPathStepDetail.getCellData(i - 1, "transWrkIndictNo") != "" ) {
                await $c.gus.cfAlertMsg("삭제하고자 하는 단계가 포함된 운송작업단계에 운송작업지시가 발생되어서 삭제할 수 없습니다.");
                return;
            }
        }

    }

    //그리드에 매핑된 dataList의 row가 신규행이면 삭제하고 아니면 삭제마크처리.
    /*
    if(ds_odrWrkPathStepDetail.getRowStatus(ds_odrWrkPathStepDetail.getRowPosition()) == "C") {
        ds_odrWrkPathStepDetail.removeRow(ds_odrWrkPathStepDetail.getRowPosition());
    } else {
        ds_odrWrkPathStepDetail.deleteRow(ds_odrWrkPathStepDetail.getRowPosition());
    }
    */
    ds_odrWrkPathStepDetail.removeRow(ds_odrWrkPathStepDetail.getRowPosition());

    //행삭제 이후 rowChange 이벤트 발생하므로 수동으로 이벤트 추가.
    scwin.ds_odrWrkPathStepDetail_OnRowPosChanged();

    await scwin.f_setWorkStepInfoRefresh2(ds_odrWrkPathStepDetail.getRowPosition());
};
