//-------------------------------------------------------------------------
// 선택된 DATASET에 ROW 복사 ( 대상 DataSet, 원본 Row, 대상 Row )
//-------------------------------------------------------------------------
scwin.f_CopyDataRow = function (dataObject, sourceRow, targetRow) {
    var v_odrWrkStpSeq = Number(dataObject.getCellData(sourceRow, "odrWrkStpSeq"));
    var v_tempSeq = (v_odrWrkStpSeq / 10) * 10;
    var colId = "";

    for(var i = 0; i < dataObject.getColCnt(); i++){
        colId = dataObject.getColumnID(i);
        if(colId == "odrWrkStpSeq"){
            dataObject.setCellData(targetRow, colId, Number(dataObject.getCellData(sourceRow, colId))+1); 
        } else if(colId == "arvWrkPlClsCd" || colId == "dptWrkPlClsCd" || colId == "dptWrkPlClsCdChange" || colId == "arvWrkPlClsCdChange" ) {
            dataObject.setCellData(targetRow, colId, " ");
        } else if(colId == "wrkPlClsCd" || colId == "wrkStpCd" 
            || colId == "dptWrkPlCd" || colId == "dptWrkPlNm" 
            || colId == "arvWrkPlCd" || colId == "arvWrkPlNm" 
            || colId == "wrkLobranCd" || colId == "wrkLobranNm"
            || colId == "internalSellLodeptCd" || colId == "internalSellLodeptNm"
            || colId == "bizDomCd" || colId == "completeYn"){

        } else if(colId == "selpchItemCd"){
            dataObject.setCellData(targetRow, colId, dataObject.getCellData(sourceRow, colId));
        } else if(colId == "selpchItemNm"){
            dataObject.setCellData(targetRow, colId, dataObject.getCellData(sourceRow, colId));
        } else {
            dataObject.setCellData(targetRow, colId, dataObject.getCellData(sourceRow, colId)); 
        } 
    }

    // 오더작업단계순번 재정의
    for(var j = 0; j < dataObject.getRowCount(); j++){
        var v_compSeq = Number(dataObject.getCellData(j, "odrWrkStpSeq")) - v_tempSeq;

        if( Number(dataObject.getCellData(j, "odrWrkStpSeq")) > v_tempSeq && v_compSeq > 0 && v_compSeq < 10 ){

            dataObject.setCellData(j, "odrWrkStpSeq", Number(dataObject.getCellData(j-1, "odrWrkStpSeq"))+1);
        }
    }
};

//-------------------------------------------------------------------------
// 수정
//-------------------------------------------------------------------------
scwin.f_Update = function () {
    var countWrkIndictNo = 0;
    var countModify = 0;
    for (var i = 0 ; i < ds_odrWrkPathStepDetail.getRowCount() ; i++ ) {

        if( ds_odrWrkPathStepDetail.getCellData(i, "transWrkIndictNo") != "" ) {
            countWrkIndictNo++;
        }
        if(Number(ds_odrWrkPathStepDetail.getCellData(i, "odrWrkStpSeq")) % 10 != 0) {
            countModify++;
        }

    }

    gr_odrCntrWrkPath.setReadOnly("column","ctrtWrkPathSeq",false);
    gr_odrWrkPathStpDetail.setDisabled(false);

    $c.gus.cfDisableBtnOnly([btn_Update]);
    $c.gus.cfEnableBtnOnly([btn_Save]);

    gr_odrCntrWrkPath.setReadOnly("column","ctrtWrkPathSeq",false);
    gr_odrWrkPathStpDetail.setDisabled(false);

    if(ds_odrWrkPathStep.getRowCount() > 0){
        gr_odrWrkPathStpDetail.setCellReadOnly(ds_odrWrkPathStepDetail.getRowPosition(),"wrkPlClsCd",true);
        gr_odrWrkPathStpDetail.setCellReadOnly(ds_odrWrkPathStepDetail.getRowPosition(),"wrkStpCd",true);
        gr_odrWrkPathStpDetail.setCellReadOnly(ds_odrWrkPathStepDetail.getRowPosition(),"selpchItemNm",true);

        scwin.gv_modifyYn = true;
    }

    gr_odrWrkPathStpDetail.setFocusedCell(ds_odrWrkPathStepDetail.getRowPosition(), "wrkLobranNm");

    var v_row = ds_odrWrkPathStepDetail.getRowPosition();
    var v_colid = "wrkLobranNm";
};


