// 저장전 validation check
//-------------------------------------------------------------------------
scwin.f_validChk = async function () {
    let ret = await $c.gus.cfValidate([gr_odrCntrWrkPath]);
    let ret2 = await $c.gus.cfValidate([gr_odrWrkPathStpDetail]);

    //오더품목  필수 입력사항을 체크
    if (ret == true && ret2 == true) {          
        return true;
    } else {
        return false;
    }
};


