// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_openCommPopUpGrid = async function (callObj, disGubun, row, pCode, pName, pClose, pAllSearch) {
    // 선언부
    var rtnList  = new Array();  // 공통POP-UP -> 요청화면 
    var chkValue = false;
    var pWhere;

    scwin.udc_objNm = callObj.org_id;

    switch (disGubun)
    {
        case 1:

            //초기화 처리
            ds_odrWrkPathStepDetail.setCellData(row,"wrkLobranCd", "");
            ds_odrWrkPathStepDetail.setCellData(row,"wrkLobranNm", "");

            callObj.setSelectId("retrieveLogisDeptInfo");

            await callObj.cfCommonPopUp(scwin.udc_AllInOne_callBackFunc  
                                    ,pCode                  // 화면에서의 ??? Code Element의  Value
                                    ,pName                  // 화면에서의 ??? Name Element의  Value
                                    ,pClose                 // 결과가 1건 일때  원도우를  AutoClose 여부    (T:Close,F:Opened)
                                    ,null                   // 검색 결과    컬럼의 보여주는    개수 (SELECT절의 순서) MAX:10 - default (2)
                                    ,null                   // Title순서  
                                    ,null                   // 보여주는 각 컬럼들의 폭    
                                    ,null                   // 컬럼중에서 숨기는    컬럼 지정   
                                    ,"A,B"                  // SQL절의 WHERE절에    원하는 조건을 선택함 MAX:8개까지 가능
                                    ,null                   // POP-UP뛰을때 원도우의   사용자 정의  폭
                                    ,null                   // POP-UP뛰을때 우도우의   사용자 정의  높이  
                                    ,null                   // 윈도우 위치 Y좌표   
                                    ,null                   // 윈도우 위치 X좌표
                                    ,null                   // 중복체크여부   ("F")
                                    ,pAllSearch                 // 전체검색허용여부 ("F")
                                    ,"작업점소,점소코드,점소명"                // POP-UP Window Title 검색어1,2    ("Win타이틀,첫번검색Nm,두번?검색Nm")
                                    ); 
            break;

        case 2:
            // 작업장 팝업   - 작업단계별 작업장 팝업
            var pWrkPlClsCd = ds_odrWrkPathStepDetail.getCellData(row,"wrkPlClsCd").trim();       // 작업구분코드
            var pBizDomCd = ds_odrWrkPathStepDetail.getCellData(row,"bizDomCd").trim();// 사업영역코드

            pWhere = pWrkPlClsCd;

            //초기화 처리
            ds_odrWrkPathStepDetail.setCellData(row,"dptWrkPlCd", "");
            ds_odrWrkPathStepDetail.setCellData(row,"dptWrkPlNm", "");

            callObj.setSelectId("retrieveWrkPlInfo");

            await callObj.cfCommonPopUp(scwin.udc_AllInOne_callBackFunc 
                                    ,pCode                  // 화면에서의 ??? Code Element의  Value
                                    ,pName                  // 화면에서의 ??? Name Element의  Value
                                    ,pClose                 // 결과가 1건 일때  원도우를  AutoClose 여부    (T:Close,F:Opened)
                                    ,null                   // 검색 결과    컬럼의 보여주는    개수 (SELECT절의 순서) MAX:10 - default (2)
                                    ,null                   // Title순서  
                                    ,null                   // 보여주는 각 컬럼들의 폭    
                                    ,null                   // 컬럼중에서 숨기는    컬럼 지정   
                                    ,pWhere                 // SQL절의 WHERE절에    원하는 조건을 선택함 MAX:8개까지 가능
                                    ,null                   // POP-UP뛰을때 원도우의   사용자 정의  폭
                                    ,null                   // POP-UP뛰을때 우도우의   사용자 정의  높이  
                                    ,null                   // 윈도우 위치 Y좌표   
                                    ,null                   // 윈도우 위치 X좌표
                                    ,null                   // 중복체크여부   ("F")
                                    ,pAllSearch                 // 전체검색허용여부 ("F")
                                    ,"작업장,작업장코드,작업장명"               // POP-UP Window Title 검색어1,2    ("Win타이틀,첫번검색Nm,두번?검색Nm")
                                    ); 
            break;

        case 3:

            // 매출귀속 부서 팝업   : 작업점소(물류점소 : 팀[T]+작업장(J)) 팝업       - 물류점소구분코드 : LO120 - 팀(T), 지점(A), 사업소(B), CY(C), CFS(F), 작업장(J) 
            var pWrkLobranCd = ds_odrWrkPathStepDetail.getCellData(row,"wrkLobranCd");    // 작업점소코드   
            pWhere = "T,J";

            //초기화 처리
            ds_odrWrkPathStepDetail.setCellData(row,"internalSellLodeptCd", "");
            ds_odrWrkPathStepDetail.setCellData(row,"internalSellLodeptNm", "");

            callObj.setSelectId("retrieveLogisDeptInfo");

            await callObj.cfCommonPopUp(scwin.udc_AllInOne_callBackFunc  
                                    ,pCode                  // 화면에서의 ??? Code Element의  Value
                                    ,pName                  // 화면에서의 ??? Name Element의  Value
                                    ,pClose                 // 결과가 1건 일때  원도우를  AutoClose 여부    (T:Close,F:Opened)
                                    ,null                   // 검색 결과    컬럼의 보여주는    개수 (SELECT절의 순서) MAX:10 - default (2)
                                    ,null                   // Title순서  
                                    ,null                   // 보여주는 각 컬럼들의 폭    
                                    ,null                   // 컬럼중에서 숨기는    컬럼 지정   
                                    ,pWhere                 // SQL절의 WHERE절에    원하는 조건을 선택함 MAX:8개까지 가능
                                    ,null                   // POP-UP뛰을때 원도우의   사용자 정의  폭
                                    ,null                   // POP-UP뛰을때 우도우의   사용자 정의  높이  
                                    ,null                   // 윈도우 위치 Y좌표   
                                    ,null                   // 윈도우 위치 X좌표
                                    ,null                   // 중복체크여부   ("F")
                                    ,pAllSearch                 // 전체검색허용여부 ("F")
                                    ,"매출귀속부서,부서코드,부서명"              // POP-UP Window Title 검색어1,2    ("Win타이틀,첫번검색Nm,두번?검색Nm")
                                    ); 
            break;

        default:
            break;
    }   

    return chkValue;
};

scwin.udc_AllInOne_callBackFunc = async function (rtnList) {
    if(scwin.udc_objNm == "udc_gr_odrWrkPathStpDetail_wrkLobranNm") {
        if ( rtnList != null) {
            if(rtnList[0].trim() != "N/A"){
                ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition(),"wrkLobranCd", rtnList[0]);  //작업점소코드
                ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition(),"wrkLobranNm", rtnList[1]);  //작업점소명
            }
        } else {
            ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition(),"wrkLobranCd", "");  //작업점소코드
            ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition(),"wrkLobranNm", "");  //작업점소명
        }
    } else if(scwin.udc_objNm == "udc_gr_odrWrkPathStpDetail_dptWrkPlNm") {
        if ( rtnList != null) {
            if(rtnList[0].trim() != "N/A"){

                ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition(),"dptWrkPlCd", rtnList[0]);   //작업장 코드
                if(!$c.gus.cfIsNull(rtnList[3]))   {
                    ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition(),"bizDomCd", rtnList[3]); //작업장 사업영역코드
                }
                if(!$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(), "wrkPlClsCd").trim())) { // 운송 단계가 아닌경우 작업장명 설정 
                    ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition(),"dptWrkPlNm", rtnList[1]);   //작업장 명
                }
                // 해당 단계의 출발지를 다음 단계의 출발지로 설정 (다음 단계가 운송 단계인 경우)
                //if(row > 1 && row < ds_odrWrkPathStepDetail.CountRow){
                    if($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition() + 1, "wrkPlClsCd").trim()) 
                        && !$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(),"dptWrkPlCd"))){
                        ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition()+1,"dptWrkPlCd", ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(),"dptWrkPlCd"));
                    }
                //}
            }
        } else {
            ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition(),"dptWrkPlCd", "");   //작업장 코드
            ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition(),"dptWrkPlNm", "");   //작업장 명
        }

        // 작업 단계 정보 재설정
        if(ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(),"dptWrkPlCd") != ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(),"dptWrkPlCd2")) {
            await scwin.f_setWorkStepInfoRefresh2( ds_odrWrkPathStepDetail.getRowPosition() );

            if( !$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition() - 1, "dptWrkPlCd")) 
                    && !$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition() - 1, "arvWrkPlCd")) ) {

            }

            if( !$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition() + 1, "dptWrkPlCd")) 
                    && !$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition() + 1, "arvWrkPlCd")) ) {

            }
        }

        if( ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(),"wrkPlClsCd") == ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition()+1,"wrkPlClsCd")
            && ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(),"wrkStpCd") == "0029" //하차
            && ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition()+1,"wrkStpCd") == "0028" //상차
        ){
            ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition()+1,"dptWrkPlNm", ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(),"dptWrkPlNm"));
            ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition()+1,"dptWrkPlCd", ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(),"dptWrkPlCd"));
            ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition()+1,"internalSellLodeptCd", ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(),"internalSellLodeptCd"));
            ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition()+1,"internalSellLodeptNm", ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(),"internalSellLodeptNm"));
        }
//이부부분
        if( ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(),"wrkPlClsCd") == ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition()+1,"wrkPlClsCd")
            && ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(),"wrkStpCd") == "0029" //하차
            && ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition()+1,"wrkStpCd") == "0028" //상차
            && ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition()+2,"wrkStpCd") == "0001" //셔틀
        ){
            ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition()+1,"dptWrkPlNm", ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(),"dptWrkPlNm"));
            ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition()+1,"dptWrkPlCd", ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(),"dptWrkPlCd"));
            ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition()+1,"internalSellLodeptCd", ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(),"internalSellLodeptCd"));
            ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition()+1,"internalSellLodeptNm", ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(),"internalSellLodeptNm"));
            ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition()+2,"dptWrkPlNm", ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(),"dptWrkPlNm"));
            ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition()+2,"dptWrkPlCd", ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(),"dptWrkPlCd"));
        } 

        if( ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(),"wrkPlClsCd") == ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition()+1,"wrkPlClsCd")
            && ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(),"wrkStpCd") == "0029" //하차
            && ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition()+1,"wrkStpCd") == "0028" //상차
            && ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition()+2,"wrkStpCd") == "0047" //육송
        ){
            ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition()+1,"dptWrkPlNm", ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(),"dptWrkPlNm"));
            ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition()+1,"dptWrkPlCd", ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(),"dptWrkPlCd"));
            ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition()+1,"internalSellLodeptCd", ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(),"internalSellLodeptCd"));
            ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition()+1,"internalSellLodeptNm", ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(),"internalSellLodeptNm"));
            ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition()+2,"dptWrkPlNm", ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(),"dptWrkPlNm"));
            ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition()+2,"dptWrkPlCd", ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(),"dptWrkPlCd"));
        } 

        if( ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(),"wrkPlClsCd") == ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition()+1,"wrkPlClsCd")
            && ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(),"wrkStpCd") == "0029" //하차
            && ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition()+1,"wrkStpCd") == "0028" //상차
            && ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition()+2,"wrkStpCd") == "0029" //하차
        ){
            ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition()+1,"dptWrkPlNm", ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(),"dptWrkPlNm"));
            ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition()+1,"dptWrkPlCd", ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(),"dptWrkPlCd"));
            ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition()+1,"internalSellLodeptCd", ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(),"internalSellLodeptCd"));
            ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition()+1,"internalSellLodeptNm", ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(),"internalSellLodeptNm"));
            ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition()+2,"dptWrkPlNm", ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(),"dptWrkPlNm"));
            ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition()+2,"dptWrkPlCd", ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(),"dptWrkPlCd"));
            ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition()+2,"internalSellLodeptCd", ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(),"internalSellLodeptCd"));
            ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition()+2,"internalSellLodeptNm", ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(),"internalSellLodeptNm"));
        }

        //여기서 경기지사 오더로 철송 이후에 작업단계수정 못하도록 함.
        if(ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(), "odrNo").substring(0,3)== "BC4" && scwin.rail_yn == "Y"
            && scwin.userId != "991166" 
            && scwin.userId != "030706" 
            && scwin.userId != "021710" 
            && scwin.userId != "101460" 
            && scwin.userId != "040971" 
            && scwin.userId != "snowmoon" 
        ){
            if(Number(ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(), "odrWrkStpSeq")) >= scwin.v_odrWrkStpSeq
                && scwin.v_odrWrkStpSeqMax != Number(ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(), "odrWrkStpSeq"))){
                await $c.win.alert("철송이후 단계를 수정하실수 없습니다.");
                await scwin.f_Retrieve();
            }
        }
    } else if(scwin.udc_objNm == "udc_gr_odrWrkPathStpDetail_internalSellLodeptNm") {
        if (rtnList != null ) {
            if(rtnList[0].trim() != "N/A"){
                ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition(),"internalSellLodeptCd", rtnList[0]); //매출귀속 부서코드
                ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition(),"internalSellLodeptNm", rtnList[1]); //매출귀속 부서명
            }
            chkValue = true;
        } else {
            ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition(),"internalSellLodeptCd", ""); //매출귀속 부서코드
            ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition(),"internalSellLodeptNm", ""); //매출귀속 부서명
        }
    } else if(scwin.udc_objNm == "udc_gr_odrWrkPathStpDetail_selpchItemNm") {
        $c.gus.cfSetGridReturnValue(rtnList, ds_odrWrkPathStepDetail, ds_odrWrkPathStepDetail.getRowPosition(), "selpchItemCd", "selpchItemNm");
    }
};



//-------------------------------------------------------------------------
// 작업장 별 작업점소, 매출귀속부서 정보를 조회한다.
// row : 데이터셋의 Row
// pCode : 화면에서의 ??? Code Element의    Value
// pName : 화면에서의 ??? Name Element의    Value
// pClose : 결과가 1건 일때  원도우를   AutoClose 여부    (T:Close,F:Opened)
// pAllSearch : 전체검색허용여부  ("F")
// pDptWrkPlsYn : 출발지(작업장) 검색 여부 (T:출발작업장,F:도착작업장)
// pOrgValueCheck : OrgValue 검색 조건 값 확인 (T : OrgValue 확인, F:확인 안함) 
//-------------------------------------------------------------------------
scwin.f_setWorkLobranInternalSellLodept = async function (row, pCode, pName, pClose, pAllSearch, pDptWrkPlsYn, pOrgValueCheck, pNoDataCloseTF, pDptWrkChangeTF) {
    // 작업장 팝업   - 작업단계별 작업장 팝업
    var pWrkPlClsCd = ds_odrWrkPathStepDetail.getCellData(row,"wrkPlClsCd").trim();       // 작업구분코드
    var pBizDomCd = ds_odrWrkPathStepDetail.getCellData(row,"bizDomCd").trim();   // 사업영역코드
    var pSelpchItemCd = ds_odrWrkPathStepDetail.getCellData(row,"selpchItemCd").trim();   // 매출입구분코드
    var pWhere;
    if($c.gus.cfIsNull(pDptWrkChangeTF))   {
        pDptWrkChangeTF = "F";
    }

    // 조회조건이 아닌경우 종료
    if(($c.gus.cfIsNull(pCode) && $c.gus.cfIsNull(pName)) 
        || pSelpchItemCd == "0000"){
        return false;
    }

    // OrgValue 동일시 검색 하지 않음.
    if(pOrgValueCheck == "T"){
        if(pDptWrkPlsYn == "T"){
            if(pCode == ds_odrWrkPathStepDetail.getOriginalCellData(row,"dptWrkPlCd")) {
                return false;   
            }
        } else {
            if(pCode == ds_odrWrkPathStepDetail.getOriginalCellData(row,"arvWrkPlCd")) {
                return false;   
            }
        }
    }

    pWhere = pWrkPlClsCd + "," + pBizDomCd; // 작업구분코드 Filter

    scwin.tempArray = [];
    scwin.tempArray.pDptWrkPlsYn = pDptWrkPlsYn;
    scwin.tempArray.pDptWrkChangeTF = pDptWrkChangeTF;
    scwin.tempArray.row = row;

    udc_f_setWorkLobranInternalSellLodept.setSelectId("retrieveWorkStepEachWorkPlaceInfo");

    await udc_f_setWorkLobranInternalSellLodept.cfCommonPopUp(scwin.udc_f_setWorkLobranInternalSellLodept_callBackFunc     // XML상의 SELECT ID  
                            ,pCode                  // 화면에서의 ??? Code Element의  Value
                            ,pName                  // 화면에서의 ??? Name Element의  Value
                            ,pClose                 // 결과가 1건 일때  원도우를  AutoClose 여부    (T:Close,F:Opened)
                            ,null                   // 검색 결과    컬럼의 보여주는    개수 (SELECT절의 순서) MAX:10 - default (2)
                            ,null                   // Title순서  
                            ,null                   // 보여주는 각 컬럼들의 폭    
                            ,null                   // 컬럼중에서 숨기는    컬럼 지정   
                            ,pWhere                 // SQL절의 WHERE절에    원하는 조건을 선택함 MAX:8개까지 가능
                            ,null                   // POP-UP뛰을때 원도우의   사용자 정의  폭
                            ,null                   // POP-UP뛰을때 우도우의   사용자 정의  높이  
                            ,null                   // 윈도우 위치 Y좌표   
                            ,null                   // 윈도우 위치 X좌표
                            ,null                   // 중복체크여부   ("F")
                            ,pAllSearch                 // 전체검색허용여부 ("F")
                            ,"작업장,작업장코드,작업장명"               // POP-UP Window Title 검색어1,2    ("Win타이틀,첫번검색Nm,두번?검색Nm")
                            ,pNoDataCloseTF         // Data건수가 0건일때 Window를 뛰우지 않음 리턴 : "N/A" 또는 null
                            ); 
};

scwin.udc_f_setWorkLobranInternalSellLodept_callBackFunc = async function (rtnList) {
    var pDptWrkPlsYn = scwin.tempArray.pDptWrkPlsYn;
    var pDptWrkChangeTF = scwin.tempArray.pDptWrkChangeTF;
    var row = scwin.tempArray.row;

    if ( rtnList != null) {
        if(rtnList[0].trim() != "N/A"){
            if(pDptWrkPlsYn == "T"){
                if(pDptWrkChangeTF == "F"){
                    ds_odrWrkPathStepDetail.setCellData(row,"dptWrkPlCd", rtnList[0]);   //작업장 코드
                    if(!$c.gus.cfIsNull(rtnList[2]))   {
                        ds_odrWrkPathStepDetail.setCellData(row,"bizDomCd", rtnList[2]); //작업장 사업영역코드
                    }

                    scwin.v_bizDomCd = rtnList[2];

                    if(!$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(row, "wrkPlClsCd").trim()))  { // 운송 단계가 아닌경우 작업장명 설정 
                        ds_odrWrkPathStepDetail.setCellData(row,"dptWrkPlNm", rtnList[1]);   //작업장 명
                    }
                }       
            } else {
                ds_odrWrkPathStepDetail.setCellData(row,"arvWrkPlCd", rtnList[0]);   //도착작업장 코드
            }

            // 매출항목이 무매출이 아닌경우 작업점소, 매출귀속부서를 자동 설정한다.
            if(ds_odrWrkPathStepDetail.getCellData(row, "selpchItemCd").trim() != "0000"){

				//타CY에서 CY셔틀구간 작업점소, 매출귀속부서를 경기지사,경기운송으로 세팅한다.
				//2015.03.17
				if(ds_odrWrkPathStepDetail.getCellData(row, "odrWrkStpSeq") == "20"
				&& rtnList[5] == "4AA"
				&& scwin.loUpperLobranCd == "4BB"){

	                // 작업점소 정보 설정
	                ds_odrWrkPathStepDetail.setCellData(row,"wrkLobranCd", "4BB");  //작업점소코드
	                ds_odrWrkPathStepDetail.setCellData(row,"wrkLobranNm", "의왕지점");  //작업점소명

	                // 매출귀속부서정보 설정
	                ds_odrWrkPathStepDetail.setCellData(row,"internalSellLodeptCd", "4B2"); //매출귀속부서코드
	                ds_odrWrkPathStepDetail.setCellData(row,"internalSellLodeptNm", "의왕운송"); //매출귀속부서명
				}else{

	                // 작업점소 정보 설정
	                if(!$c.gus.cfIsNull(rtnList[5])){
	                    ds_odrWrkPathStepDetail.setCellData(row,"wrkLobranCd", rtnList[5]);  //작업점소코드
	                    ds_odrWrkPathStepDetail.setCellData(row,"wrkLobranNm", rtnList[6]);  //작업점소명
	                }   
	                // 매출귀속부서정보 설정
	                if(!$c.gus.cfIsNull(rtnList[7])){
	                    ds_odrWrkPathStepDetail.setCellData(row,"internalSellLodeptCd", rtnList[7]); //매출귀속부서코드
	                    ds_odrWrkPathStepDetail.setCellData(row,"internalSellLodeptNm", rtnList[8]); //매출귀속부서명
	                }

				}

            }

        }

    } else {
        if(pDptWrkChangeTF == "F"){
            ds_odrWrkPathStepDetail.setCellData(row,"dptWrkPlCd", "");   //작업장 코드
            ds_odrWrkPathStepDetail.setCellData(row,"dptWrkPlNm", "");   //작업장 명
        }
        ds_odrWrkPathStepDetail.setCellData(row,"wrkLobranCd", "");  //작업점소코드
        ds_odrWrkPathStepDetail.setCellData(row,"wrkLobranNm", "");  //작업점소명
        ds_odrWrkPathStepDetail.setCellData(row,"internalSellLodeptCd", ""); //매출귀속부서코드
        ds_odrWrkPathStepDetail.setCellData(row,"internalSellLodeptNm", ""); //매출귀속부서명
    }
};


