scwin.f_setWorkLobranNoDataAutoClose = async function (row, pCode, pName, pClose, pAllSearch, pDptWrkPlsYn, pOrgValueCheck, pNoDataCloseTF, pDptWrkChangeTF) {
    // 작업장 팝업   - 작업단계별 작업장 팝업
