//오더번호검색 팝업열기
scwin.f_openPopUpOdrNo = async function (e) {
    var args = new Array();
    args[0] = ed_cnd_cntrNo.getValue().trim();   //컨테이너번호
    args[1] = acb_cnd_odrKndCd.getValue(); //오더종류

    var opts = {
        id : "smpPop", 
        popupName : "오더검색팝업", //  팝업 타이틀에 표시
        type : "browserPopup",  // window popup , 해당 옵션이 없으면 layer popup pageFramePopup  browserPopup
        modal : true
        , width : 1240//1240
        , height : 600
    };

    //초기화처리.
    ed_cnd_cntrNo.setValue("");

    let rtnList = await $c.win.openPopup("/ui/ds/sd/odrmgnt/odrreg/sd_402_01_31p.xml", opts, args);
    if (rtnList != null) {
        if(rtnList[0] != "N/A"){
            ed_odrNo.setValue(rtnList[0]);  // 오더번호
            hid_cntrSeq.setValue(rtnList[2]);  // 컨테이너 SEQ
        }
    }
};


//컨테이너번호 EMEdit OnKillFocus시
scwin.ed_cnd_cntrNo_onblur = async function (e) {
    if(!$c.gus.cfIsNull(ed_cnd_cntrNo.getValue().trim())) {
        await scwin.f_openPopUpOdrNo();
    }
};

scwin.ed_cnd_cntrNo_onkeyup = function (e) {
    ed_cnd_cntrNo.setValue(ed_cnd_cntrNo.getValue().toUpperCase());
};



//오더번호 EMEdit KeyPressUp 시
scwin.ed_odrNo_onkeydown = async function (e) {
    if(e.keyCode == 13) {
        await scwin.f_Retrieve();
    }
};













