//for=ds_odrCntrWrkPath event=OnRowPosChanged
scwin.ds_odrCntrWrkPath_onrowpositionchange = async function (info) {
    var row = info.newRowIndex;

    if(Number(ds_odrCntrWrkPath.getCellData(row, "ctrtWrkPathSeq")) > 0){

        if(ds_odrWrkPathStepDetail.getRowCount() > 0){
            // 이미 작업단계가 존재함.

        } else {
            // 작업단계 검색 조건 설정
            dma_searchWrkStep.set("odrNo", ds_odrCntrWrkPath.getCellData(row, "odrNo"));
            dma_searchWrkStep.set("cntrSeq", ds_odrCntrWrkPath.getCellData(row, "cntrSeq"));
            dma_searchWrkStep.set("odrWrkPathSeq", ds_odrCntrWrkPath.getCellData(row, "odrWrkPathSeq"));
            dma_searchWrkStep.set("ctrtNo", ds_odrCntrWrkPath.getCellData(row, "ctrtNo"));
            dma_searchWrkStep.set("ctrtWrkPathSeq", ds_odrCntrWrkPath.getCellData(row, "ctrtWrkPathSeq"));

            await scwin.f_RetrieveWorkStep();
        }

        totalRows2.setValue(ds_odrWrkPathStepDetail.getRowCount()); 
    }

    // 해당 품명의 실적 발생여부를 확인하여 수정 가능 항목을 설정한다.
    // 실적 발생시 수정할 수 없다.
    // 실적 발생여부를 조회하여 수정항목을 설정한다.
    if(row > -1 && btn_Update.getDisabled()){
        if(scwin.f_chkResultsConfirmationCommodity(row)){
            gr_odrCntrWrkPath.setReadOnly("column","ctrtWrkPathSeq",true);
            gr_odrWrkPathStpDetail.setDisabled(true);
        } else {
            gr_odrCntrWrkPath.setReadOnly("column","ctrtWrkPathSeq",false);
            gr_odrWrkPathStpDetail.setDisabled(false);
        }
    }
};



//for=gr_odrWrkPathStpDetail event=OnClick
scwin.gr_odrWrkPathStpDetail_oncellclick = function (rowIndex, columnIndex, columnId) {
    var row = rowIndex;
    var colid = columnId;

    scwin.gr_odrWrkPathStpDetailColIdx = columnIndex;
    scwin.gr_odrWrkPathStpDetailRowIdx = rowIndex;

    // 필터 클리어는 gr_odrWrkPathStpDetail_onafteredit 함수내에서 처리하므로 불필요.
    // 작업단계 Row가 변경될때 해당 작업장구분별 작업단계로 Filter 처리
    /*
    if(ds_odrWrkPathStepDetail.CountRow > 0){
        ds_LkStepNo.filter();
    }
    */

    //현행포함 이후의 행들에 실적이 있을시 수정할 수 없다.
    var modifyYn = true;
    for(var i = row ; i < ds_odrWrkPathStepDetail.getRowCount() ; i++ ) {
        if( ds_odrWrkPathStepDetail.getCellData(i, "transWrkIndictNo") != "" ) {
            modifyYn = false;
        }
    }


    if(modifyYn) {
        gr_odrWrkPathStpDetail.setCellReadOnly(row,"wrkPlClsCd",false);
        gr_odrWrkPathStpDetail.setCellReadOnly(row,"wrkStpCd",false);
        gr_odrWrkPathStpDetail.setCellReadOnly(row,"dptWrkPlNm",false);
        gr_odrWrkPathStpDetail.setCellReadOnly(row,"wrkLobranNm",false);
        gr_odrWrkPathStpDetail.setCellReadOnly(row,"internalSellLodeptNm",false);

        gr_odrWrkPathStpDetail.setCellReadOnly(row,"wrkStDt",false);
        gr_odrWrkPathStpDetail.setCellReadOnly(row,"wrkStHh",false);
        gr_odrWrkPathStpDetail.setCellReadOnly(row,"wrkEndDt",false);
        gr_odrWrkPathStpDetail.setCellReadOnly(row,"wrkEndHh",false);

        gr_odrWrkPathStpDetail.setCellReadOnly(row,"fullEmptyClsCd",false);
        gr_odrWrkPathStpDetail.setCellReadOnly(row,"selpchItemNm",false);
        gr_odrWrkPathStpDetail.setCellReadOnly(row,"smsYn",false);
    }

    if(row > -1){

        //작업단계 수정모드 설정
        scwin.f_checkWorkStepEditMode(row);

        if(ds_odrWrkPathStep.getRowCount() == 0){

            if(ds_odrWrkPathStepDetail.getCellData(row, "wrkPlClsCd").trim() == ""){  // 작업구분이 운송인 경우 작업장 입력불가
                gr_odrWrkPathStpDetail.setCellReadOnly(row,"dptWrkPlNm",true);
            } else {
                gr_odrWrkPathStpDetail.setCellReadOnly(row,"dptWrkPlNm",false);
            }
        }

        if( ds_odrWrkPathStepDetail.getCellData(row, "selpchItemCd").trim() == SdConstants.SELPCH_ITEM_CD_NOSELL
                && !$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(row, "wrkPlClsCd").trim()) ) {   // 매출입항목이 무매출이고, 운송단계가 아닌인 경우 작업점소, 매출귀속부서 입력 불가
            gr_odrWrkPathStpDetail.setCellReadOnly(row,"wrkLobranNm",true);
            gr_odrWrkPathStpDetail.setCellReadOnly(row,"internalSellLodeptNm",true);
        } else {
            gr_odrWrkPathStpDetail.setCellReadOnly(row,"wrkLobranNm",false);
            gr_odrWrkPathStpDetail.setCellReadOnly(row,"internalSellLodeptNm",false);
            gr_odrWrkPathStpDetail.setCellReadOnly(row,"smsYn",false);
        }
    }

    if(!modifyYn) {

        gr_odrWrkPathStpDetail.setCellReadOnly(row,"wrkPlClsCd",true);
        gr_odrWrkPathStpDetail.setCellReadOnly(row,"wrkStpCd",true);
        gr_odrWrkPathStpDetail.setCellReadOnly(row,"selpchItemNm",true);
        gr_odrWrkPathStpDetail.setCellReadOnly(row,"dptWrkPlNm",true);
        gr_odrWrkPathStpDetail.setCellReadOnly(row,"wrkLobranNm",true);
        gr_odrWrkPathStpDetail.setCellReadOnly(row,"internalSellLodeptNm",true);

        gr_odrWrkPathStpDetail.setCellReadOnly(row,"wrkStDt",true);
        gr_odrWrkPathStpDetail.setCellReadOnly(row,"wrkStHh",true);
        gr_odrWrkPathStpDetail.setCellReadOnly(row,"wrkEndDt",true);
        gr_odrWrkPathStpDetail.setCellReadOnly(row,"wrkEndHh",true);

        gr_odrWrkPathStpDetail.setCellReadOnly(row,"fullEmptyClsCd",true);
        gr_odrWrkPathStpDetail.setCellReadOnly(row,"selpchItemNm",true);
        gr_odrWrkPathStpDetail.setCellReadOnly(row,"smsYn",false);  
    }
};


scwin.gr_odrWrkPathStpDetail_onbeforeedit = function (rowIndex, columnIndex, value) {
    //작업단계 item 필터링 처리.
    if(columnIndex == 7) {
        scwin.gr_odrWrkPathStpDetail_wrkStpCd_setFilter(rowIndex);
    }
};

//for=gr_odrWrkPathStpDetail event=OnCloseUp
//Grid Column의 EditStyle이 Combo 또는 Lookup일 경우 Combo가 닫힐 때 발생한다.
//Grid에서 Combo를 사용해 Data를 선택시 OnCloseUp 이벤트를 사용해 다른 작업을 수행할수 있도록 한다.
//=> onafteredit 함수내에서 셋팅처리.(사유: onafteredit 함수내에서 필터 초기화처리 로직 존재.)
scwin.gr_odrWrkPathStpDetail_oneditend = function (rowIndex, columnIndex, value) {
    if(columnIndex == 6) {
        //empty 값 셋팅위한 최상위 row 추가. 
        if(ds_LkStepNo.getCellData(0, "initYN") == "") {
            ds_LkStepNo.insertRow(0);
            ds_LkStepNo.setCellData(0, "initYN", "Y");
            ds_LkStepNo.reform();
        }
    } else if(columnIndex == 7) {
        //empty 값 셋팅위한 최상위 row 추가. 
        if(value == "" && ds_LkStepNo.getCellData(0, "initYN") == "") {
            ds_LkStepNo.insertRow(0);
            ds_LkStepNo.setCellData(0, "initYN", "Y");
            ds_LkStepNo.reform();
        }
    }
};

