};


//for=gr_odrWrkPathStpDetail event=OnExit 처리위한 로직2.(별도 함수 호출위한 로직)
//그리드 cell focus out 처리(상기 로직1의 변경되기전 정보가 없는 경우도 호출함.)
scwin.gr_odrWrkPathStpDetail_onafteredit = async function (rowIndex, columnIndex, value) {

    /************************************************************************
    * for=gr_odrWrkPathStpDetail event=OnCloseUp 이벤트 시작.
    ************************************************************************/
    // 작업장구분 또는 작업단계 수정(focus out) 시
    if(columnIndex == 6 || columnIndex == 7) {
        //작업단계 item 필터링 해제 및 empty 값 셋팅된 row 삭제 처리.
        if(ds_LkStepNo.getRowCount() < ds_LkStepNo.getAllJSON().length) {
            ds_LkStepNo.clearFilter();

            //작업단계 item 보여주기전 empty 값 셋팅된 row 삭제처리.
            for(var i=0;i<ds_LkStepNo.getRowCount();i++) {
                if(ds_LkStepNo.getCellData(i, "initYN") == "Y") {
                    ds_LkStepNo.removeRow(i);
                }
            }

            ds_LkStepNo.reform();
        }

        // 작업장 구분
        if(columnIndex == 6) {
            if(scwin.gr_odrWrkPathStpDetail_beforeCellChgInfos != undefined && scwin.gr_odrWrkPathStpDetail_beforeCellChgInfos != null && 
               scwin.gr_odrWrkPathStpDetail_beforeCellChgInfos != "" && Object.keys(scwin.gr_odrWrkPathStpDetail_beforeCellChgInfos).length > 0) {
                    ds_odrWrkPathStepDetail.setCellData(rowIndex,"dptWrkPlCd", "");
                    ds_odrWrkPathStepDetail.setCellData(rowIndex,"dptWrkPlNm", "");
                    ds_odrWrkPathStepDetail.setCellData(rowIndex,"arvWrkPlCd", "");
                    ds_odrWrkPathStepDetail.setCellData(rowIndex,"arvWrkPlNm", "");
                    ds_odrWrkPathStepDetail.setCellData(rowIndex,"wrkLobranCd", "");
                    ds_odrWrkPathStepDetail.setCellData(rowIndex,"wrkLobranNm", "");

                    ds_odrWrkPathStepDetail.setCellData(rowIndex,"internalSellLodeptCd", "");
                    ds_odrWrkPathStepDetail.setCellData(rowIndex,"internalSellLodeptNm", "");

                    // 작업 단계 정보 재설정
                    await scwin.f_setWorkStepInfoRefresh2(rowIndex);
            }
        }
        // 작업단계 
        else if(columnIndex == 7) {
            var colValue = ds_odrWrkPathStepDetail.getCellData(rowIndex, "wrkStpCd");

            if ( colValue == "0001" || colValue == "0002" || colValue == "0003" || colValue == "0047" ) {

                ds_odrWrkPathStepDetail.setCellData(rowIndex, "dptWrkPlClsCd", " ");
                ds_odrWrkPathStepDetail.setCellData(rowIndex, "arvWrkPlClsCd", " ");

            }
            await scwin.f_setWorkStepInfoRefresh2(rowIndex);
        }
    }
    /************************************************************************
    * for=gr_odrWrkPathStpDetail event=OnCloseUp 이벤트 끝.
    ************************************************************************/


    if(scwin.gr_odrWrkPathStpDetail_beforeCellChgInfos != undefined && scwin.gr_odrWrkPathStpDetail_beforeCellChgInfos != null && 
       scwin.gr_odrWrkPathStpDetail_beforeCellChgInfos != "" && Object.keys(scwin.gr_odrWrkPathStpDetail_beforeCellChgInfos).length > 0) {

        var cellRow = scwin.gr_odrWrkPathStpDetail_beforeCellChgInfos.rowIndex;
        var cellID = scwin.gr_odrWrkPathStpDetail_beforeCellChgInfos.colID;
        var cellOldVal = scwin.gr_odrWrkPathStpDetail_beforeCellChgInfos.oldValue;

        if(rowIndex == cellRow && gr_odrWrkPathStpDetail.getColumnID(columnIndex) == cellID) {
            await scwin.gr_odrWrkPathStpDetail_OnExit(cellRow, cellID, cellOldVal);
        }
    }
};

scwin.gr_odrWrkPathStpDetail_OnExit = async function (row,colid,olddata) {
    var pName = ds_odrWrkPathStepDetail.getCellData(row,colid);
    var pOrgName = olddata;
    var chkPopup = true;

    //작업단계 수정모드 설정
    scwin.f_checkWorkStepEditMode(row);

    switch (colid) {
        case "wrkLobranNm":
            if (pName != "" && pName != pOrgName)   {
                await scwin.f_openCommPopUpGrid(udc_gr_odrWrkPathStpDetail_wrkLobranNm, 1, row, '', pName, 'T', 'T');
            } else if (pName == "")   {
                ds_odrWrkPathStepDetail.setCellData(row,"wrkLobranCd", "");
            }
            break;
        case "dptWrkPlNm":    
            if (pName != "" && pName != pOrgName)   {
                await scwin.f_openCommPopUpGrid(udc_gr_odrWrkPathStpDetail_dptWrkPlNm, 2, row, '', pName, 'T', 'T');
            } else if (pName == "")   {
                ds_odrWrkPathStepDetail.setCellData(row,"dptWrkPlCd", "");
            }

            break;
        case "internalSellLodeptNm":
            if (pName != "" && pName != pOrgName)   {
                await scwin.f_openCommPopUpGrid(udc_gr_odrWrkPathStpDetail_internalSellLodeptNm, 3, row, '', pName, 'T', 'T');
            } else if (pName == "")   {
                ds_odrWrkPathStepDetail.setCellData(row,"internalSellLodeptCd", "");
            }
            break;
        case "selpchItemNm":

            var code = "";
            var name = "";

            if(ds_odrWrkPathStepDetail.getCellData(row,"selpchItemCd") != null && ds_odrWrkPathStepDetail.getCellData(row,"selpchItemCd") != undefined && ds_odrWrkPathStepDetail.getCellData(row,"selpchItemCd") != "") {
                code = ds_odrWrkPathStepDetail.getCellData(row,"selpchItemCd");
            }

            if(ds_odrWrkPathStepDetail.getCellData(row,"selpchItemNm") != null && ds_odrWrkPathStepDetail.getCellData(row,"selpchItemNm") != undefined && ds_odrWrkPathStepDetail.getCellData(row,"selpchItemNm") != "") {
                name = ds_odrWrkPathStepDetail.getCellData(row,"selpchItemNm");
            }

            ds_odrWrkPathStepDetail.setCellData(row, "selpchItemCd", "");
            ds_odrWrkPathStepDetail.setCellData(row, "selpchItemNm", "");

            scwin.udc_objNm = "udc_gr_odrWrkPathStpDetail_selpchItemNm";
            udc_gr_odrWrkPathStpDetail_selpchItemNm.setSelectId("retrieveCtrtSelpchItemInfo");

            await udc_gr_odrWrkPathStpDetail_selpchItemNm.cfCommonPopUp(scwin.udc_AllInOne_callBackFunc,   
                                    '', 
                                    name.trim(),   
                                    "T",        
                                    '7',        
                                    "매출항목코드,매출항목명",     
                                    '150,170',  
                                    null,       
                                    //  ',,,1,0,'+ ds_LkStepNo.NameValue(ds_LkStepNo.RowPosition,"topWrkStpCd"),
                                    '1,0,1,1',   
                                    '440',  
                                    '500',  
                                    null,       
                                    null,
                                    null,
                                    "F",
                                    "매출항목,매출항목코드,매출항목명");
            break;
        default:
            break;
    } 
    //return chkPopup;
};

