scwin.gr_odrWrkPathStpDetail_wrkStpCd_setFilter = function (rowIndex) {
    if(ds_odrWrkPathStepDetail.getRowCount() > 0) {
        var fn_colFilter = function(cellData, tmpParam, rowIdx){
            var v_wrkPlClsCd = ds_odrWrkPathStepDetail.getCellData(rowIndex, "wrkPlClsCd").trim();
            var v_fltrCd1 = "";

            // 작업장구분 코드로 FLTR_CD_1 값 조회 
            if(v_wrkPlClsCd != ""){
                for(i = 0 ; i < ds_wrkPlClsCd.getRowCount(); i++){
                    if(v_wrkPlClsCd == ds_wrkPlClsCd.getCellData(i,"cd")){
                        v_fltrCd1 = ds_wrkPlClsCd.getCellData(i,"fltrCd1");
                        break;
                    }
                }
            }

            if(v_fltrCd1 == "02"){  // 하역 (작업단계코드 : 01)
                if (cellData == "01") {
                    return true;
                } else {
                    return false;
                }
            } else if(v_fltrCd1 != "02" && v_fltrCd1 != ""){    // 본관,포장 (작업단계코드 : 03,04)
                if (cellData == "03") {
                    return true;
                } else {
                    return false;
                }
            } else {    // 운송 (작업단계코드 : 02)
                if (cellData == "02") {
                    return true;   
                } else {
                    return false;
                }
            }
            // return이 true인 경우 적용하고 false인 경우 넘김
        };

        ds_LkStepNo.setColumnFilter( 
            {type:'func', colIndex:'topWrkStpCd', key:fn_colFilter, condition:'and'}
        );

        ds_LkStepNo.reform();
    }
};


scwin.gr_odrWrkPathStpDetail_wrkStpCd_setFormatter = function (data, formattedData, rowIndex, colIndex) {
    if(colIndex == 7) {
        var sRtn = formattedData;
        if(ds_odrWrkPathStepDetail.getCellData(rowIndex,"wrkStpCd") == "" && formattedData.trim() == ":") {
            sRtn = "";
        }
        return sRtn;
    }  
};

