        await $c.gus.cfAlertMsg(MSG_CM_ERR_003, new Array("조회결과"));

        scwin.f_FieldClear();

        // 오더정보 초기화
        lay_realMchtclntNm.setValue("");
        lay_ctrtClntNm.setValue("");
        lay_ctrtNo.setValue("");
        lay_odrKndNm.setValue("");

    } else {    
        // 오더 종류가 내수운송인 경우 수요가로 명칭 변환
        if(ds_order.getCellData(0, "odrKndCd").substr(0,1) == "D"){
            td_realMchtClntNm.setValue("수요가");
            // 수요가명 설정
            lay_realMchtclntNm.setValue(ds_order.getCellData(0, "dmndNm"));
            // 수요가 코드 설정
            hid_realMchtclntNo.setValue(ds_order.getCellData(0, "dmndNo"));
        } else {
            td_realMchtClntNm.setValue("실화주");
            // 실화주명 설정
            lay_realMchtclntNm.setValue(ds_order.getCellData(0, "realMchtClntNm"));
            // 실화주 코드 설정
            hid_realMchtclntNo.setValue(ds_order.getCellData(0, "realMchtClntNo"));
        }

        scwin.f_setDisplayOdrKndCd(ds_order.getCellData(0, "odrKndCd"));

        // 계약거래처명 설정
        lay_ctrtClntNm.setValue(ds_order.getCellData(0, "ctrtClntNm"));
        // 계약번호 설정
        lay_ctrtNo.setValue(ds_order.getCellData(0, "ctrtNo"));
        // 오더종류명 설정
        lay_odrKndNm.setValue(ds_order.getCellData(0, "odrKndNm"));

        // 계약거래처 코드 설정
        hid_ctrtClntNo.setValue(ds_order.getCellData(0, "ctrtClntNo"));
        // 계약번호 설정
        hid_ctrtNo.setValue(ds_order.getCellData(0, "ctrtNo"));
        // 오더종류코드 설정
        hid_odrKndCd.setValue(ds_order.getCellData(0, "odrKndCd"));

        if(ds_order.getCellData(0, "odrDelYn") == DsConstants.YN_YES) {
            gr_odrCntrWrkPath.setReadOnly("column","ctrtWrkPathSeq",true);
            gr_odrWrkPathStpDetail.setDisabled(true);
            $c.gus.cfDisableBtnOnly([btn_InsertRow, btn_DeleteRow, btn_UndoMark]); 
        } else {
            gr_odrCntrWrkPath.setReadOnly("column","ctrtWrkPathSeq",false);
            gr_odrWrkPathStpDetail.setDisabled(false);
            $c.gus.cfEnableBtnOnly([btn_InsertRow, btn_DeleteRow, btn_UndoMark]);
        }
    }
};

//for=ds_odrCommodity event=OnLoadCompleted
scwin.ds_odrCommodity_ondataload = async function () {
    //dataList onload 수행이 선행된 이후 sbm_retrieve 트랜잭션 완료되므로 최초 init 시 return 처리.
    if(!scwin.f_Retrieve_submitFlag) {
        return;
    }

    var rowCnt = ds_odrCommodity.getRowCount();
    if(rowCnt > 0){
        var nRow = 0;
        for(var i = 0; i < rowCnt; i++){
            nRow = ds_odrCntrSummary.getRowCount();
            ds_odrCntrSummary.insertRow(nRow);
            ds_odrCntrSummary.setCellData(nRow, "odrNo", ds_odrCommodity.getCellData(i, "odrNo"));    // 오더번호
            ds_odrCntrSummary.setCellData(nRow, "cntrNo", ds_odrCommodity.getCellData(i, "cntrNo"));  // 컨테이너번호

            ds_odrCntrSummary.setCellData(nRow, "cntrSizCd", ds_odrCommodity.getCellData(i, "cntrSizCd"));    // 컨테이너SIZE코드
            ds_odrCntrSummary.setCellData(nRow, "cntrTypCd", ds_odrCommodity.getCellData(i, "cntrTypCd"));    // 컨테이너TYPE코드
            ds_odrCntrSummary.setCellData(nRow, "fullEmptyClsCd", ds_odrCommodity.getCellData(i, "fullEmptyClsCd"));  // FULLEMPTY구분코드
            ds_odrCntrSummary.setCellData(nRow, "qty", ds_odrCommodity.getCellData(i, "qty"));    // 수량

            ds_odrCntrSummary.setCellData(nRow, "wrkStDt", ds_odrCommodity.getCellData(i, "wrkStDt"));    // 작업시작일자
            ds_odrCntrSummary.setCellData(nRow, "wrkStHh", ds_odrCommodity.getCellData(i, "wrkStHh"));    // 작업시작시간
            ds_odrCntrSummary.setCellData(nRow, "wrkEndDt", ds_odrCommodity.getCellData(i, "wrkEndDt"));  // 작업종료일자
            ds_odrCntrSummary.setCellData(nRow, "wrkEndHh", ds_odrCommodity.getCellData(i, "wrkEndHh"));  // 작업종료시간

        }

        ds_odrCntrSummary.reform();
    }
};


