scwin.cusTimeFormatter = function (data, formattedData, rowIndex, colIndex) {
    if(data != undefined && data != null && data != "") {
        if(data.length == 0) {
            formattedData = "";
        } else if(data.length > 4) {
            formattedData = data.substr(0,2) + ":" + data.substr(2,2);
        } else if(data.length < 4) {
            formattedData = "";
        }
    } else {
        formattedData = "";
    }

    return formattedData;
};

