        ds_odrWrkPathStepDetail.setCellData(i, "wrkDstClsCd", ds_odrWrkPathStepDetail.getCellData(i, "wrkDstClsCd") == "" ?ds_odrWrkPathStepDetail.getCellData(i, "wrkDstClsCd"):ds_odrWrkPathStepDetail.getCellData(i, "wrkDstClsCd").substr(0,1));
