//사용자 함수임.
//for=ds_odrWrkPathStepDetail event=OnRowPosChanged
scwin.ds_odrWrkPathStepDetail_OnRowPosChanged = function () {
    var modifyYn = true;

    for(var i=0;i<ds_odrWrkPathStepDetail.getRowCount();i++) {
        //현행포함 이후의 행들에 실적이 있을시 수정할 수 없다.
        modifyYn = true;

        if( ds_odrWrkPathStepDetail.getCellData(i, "transWrkIndictNo") != "" ) {
            modifyYn = false;
        }

        if(modifyYn) {
            gr_odrWrkPathStpDetail.setCellReadOnly(i,"wrkPlClsCd",false);
            gr_odrWrkPathStpDetail.setCellReadOnly(i,"wrkStpCd",false);
            gr_odrWrkPathStpDetail.setCellReadOnly(i,"dptWrkPlNm",false);
            gr_odrWrkPathStpDetail.setCellReadOnly(i,"wrkLobranNm",false);
            gr_odrWrkPathStpDetail.setCellReadOnly(i,"internalSellLodeptNm",false);

            gr_odrWrkPathStpDetail.setCellReadOnly(i,"wrkStDt",false);
            gr_odrWrkPathStpDetail.setCellReadOnly(i,"wrkStHh",false);
            gr_odrWrkPathStpDetail.setCellReadOnly(i,"wrkEndDt",false);
            gr_odrWrkPathStpDetail.setCellReadOnly(i,"wrkEndHh",false);

            gr_odrWrkPathStpDetail.setCellReadOnly(i,"fullEmptyClsCd",false);
            gr_odrWrkPathStpDetail.setCellReadOnly(i,"selpchItemNm",false);
            gr_odrWrkPathStpDetail.setCellReadOnly(i,"smsYn",false);
        }



        //작업단계 수정모드 설정
        scwin.f_checkWorkStepEditMode(i);

        if(ds_odrWrkPathStep.getRowCount() == 0){
            if(ds_odrWrkPathStepDetail.getCellData(i, "wrkPlClsCd").trim() == ""){  // 작업구분이 운송인 경우 작업장 입력불가
                gr_odrWrkPathStpDetail.setCellReadOnly(i,"dptWrkPlNm",true);
            } else {
                gr_odrWrkPathStpDetail.setCellReadOnly(i,"dptWrkPlNm",false);
            }
        }


        if( ds_odrWrkPathStepDetail.getCellData(i, "selpchItemCd").trim() == SdConstants.SELPCH_ITEM_CD_NOSELL
                && !$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i, "wrkPlClsCd").trim()) ) {   // 매출입항목이 무매출이고, 운송단계가 아닌인 경우 작업점소, 매출귀속부서 입력 불가
            gr_odrWrkPathStpDetail.setCellReadOnly(i,"wrkLobranNm",true);
            gr_odrWrkPathStpDetail.setCellReadOnly(i,"internalSellLodeptNm",true);
        } else {
            gr_odrWrkPathStpDetail.setCellReadOnly(i,"wrkLobranNm",false);
            gr_odrWrkPathStpDetail.setCellReadOnly(i,"internalSellLodeptNm",false);
            gr_odrWrkPathStpDetail.setCellReadOnly(i,"smsYn",false);
        }


        if(!modifyYn) {

            gr_odrWrkPathStpDetail.setCellReadOnly(i,"wrkPlClsCd",true);
            gr_odrWrkPathStpDetail.setCellReadOnly(i,"wrkStpCd",true);
            gr_odrWrkPathStpDetail.setCellReadOnly(i,"selpchItemNm",true);
            gr_odrWrkPathStpDetail.setCellReadOnly(i,"dptWrkPlNm",true);
            gr_odrWrkPathStpDetail.setCellReadOnly(i,"wrkLobranNm",true);
            gr_odrWrkPathStpDetail.setCellReadOnly(i,"internalSellLodeptNm",true);

            gr_odrWrkPathStpDetail.setCellReadOnly(i,"wrkStDt",true);
            gr_odrWrkPathStpDetail.setCellReadOnly(i,"wrkStHh",true);
            gr_odrWrkPathStpDetail.setCellReadOnly(i,"wrkEndDt",true);
            gr_odrWrkPathStpDetail.setCellReadOnly(i,"wrkEndHh",true);

            gr_odrWrkPathStpDetail.setCellReadOnly(i,"fullEmptyClsCd",true);
            gr_odrWrkPathStpDetail.setCellReadOnly(i,"selpchItemNm",true);
            gr_odrWrkPathStpDetail.setCellReadOnly(i,"smsYn",false);  
        }
    }
};

